export function getVocabByDay(day) {
  return vocabulary.filter(v => v.day === day);
}

export function getVocabByCategory(cat) {
  return cat === 'all' ? vocabulary : vocabulary.filter(v => v.category === cat);
}

export function getVocabByDayRange(startDay, endDay) {
  return vocabulary.filter(v => v.day >= startDay && v.day <= endDay);
}

